import{_ as o,o as r,c as a,a2 as t}from"./chunks/framework.IwO0Hdn_.js";const u=JSON.parse('{"title":"[LOGIC / BUSINESS] F-06.3 — Comentarios en Códigos de Error","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-06.3_error_codes_comentarios.md","filePath":"backlog/F-06.3_error_codes_comentarios.md","lastUpdated":null}'),n={name:"backlog/F-06.3_error_codes_comentarios.md"};function i(d,e,c,s,l,m){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="logic-business-f-06-3-—-comentarios-en-codigos-de-error" tabindex="-1">[LOGIC / BUSINESS] F-06.3 — Comentarios en Códigos de Error <a class="header-anchor" href="#logic-business-f-06-3-—-comentarios-en-codigos-de-error" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-06.3 — Comentarios en Códigos de Error&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-06 — Catálogo de Códigos de Error (CRUD)</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Secundaria:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel + Base de Datos)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-06.2_error_codes_detalle_crud.html">F-06.2</a></td><td>Vista detalle del error code donde se incrusta el componente de comentarios</td></tr><tr><td><a href="./F-03.3_editor_rich_text.html">F-03.3</a></td><td>Editor TipTap 2 instalado</td></tr><tr><td><a href="./F-04.4_hilo_comentarios.html">F-04.4</a></td><td>Componente <code>CommentSection</code> reutilizable ya implementado y probado</td></tr><tr><td><a href="./F-05.5_usuarios_mock_session.html">F-05.5</a></td><td>Usuario autenticado para autoría y <code>ErrorCodeCommentPolicy</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Could</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero poder añadir comentarios a un código de error específico Para documentar notas adicionales, soluciones aplicadas o información de contexto sobre ese tipo de error concreto</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Añadir comentario):</strong> Dado que estoy en el detalle de un error code, cuando escribo un comentario en el editor TipTap y pulso &quot;Añadir&quot;, entonces el comentario aparece en el hilo con fecha y nombre del autor.</li><li>[ ] <strong>Escenario 2 (Hilo cronológico):</strong> Dado que un error code tiene varios comentarios, cuando se carga el detalle, entonces los comentarios aparecen ordenados cronológicamente (más antiguo arriba, más reciente abajo) con el nombre del usuario y la fecha.</li><li>[ ] <strong>Escenario 3 (Editar propio comentario):</strong> Dado que soy el autor de un comentario, cuando pulso el icono de editar, entonces puedo modificar el contenido. No puedo editar comentarios de otros usuarios.</li><li>[ ] <strong>Escenario 4 (Input sticky):</strong> El campo de nuevo comentario está siempre visible al fondo del panel de comentarios, aunque la lista de comentarios sea larga (sticky bottom).</li><li>[ ] <strong>Escenario 5 (Rich text):</strong> El editor de comentarios usa TipTap 2 con Alpine.js bridge (mismo que F-04.5), con soporte de negrita, cursiva, listas e imágenes (máx. 2 MB por imagen, 10 MB total).</li><li>[ ] <strong>Requisito Técnico:</strong> Componente Livewire <code>ErrorCodeCommentSection</code> reutilizando la lógica de <code>CommentSection</code> (F-04.4). Tabla <code>error_code_comments</code> (F-00.2). <code>ErrorCodeCommentPolicy@update</code> verifica autoría. Sanitizar HTML con HTMLPurifier. La sección de comentarios se renderiza en la vista <code>/error-codes/{id}</code> como componente separado.</li></ul><hr><p><strong>MoSCoW:</strong> <code>COULD</code><strong>Sprint:</strong> Sprint 4</p><p><strong>Notas:</strong></p><ul><li>Esta feature comparte exactamente la misma lógica de negocio que F-04.4 (hilo de comentarios del histórico). Se puede reutilizar el componente <code>CommentSection</code> con una prop <code>$model</code> que acepta tanto <code>ArchivedLog</code> como <code>ErrorCode</code>.</li><li>La tabla <code>error_code_comments</code> es separada de <code>comments</code> para mantener la integridad referencial clara y permitir evolución independiente.</li></ul>',16)])])}const g=o(n,[["render",i]]);export{u as __pageData,g as default};
